import{_ as s,o,c as e,a2 as a}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Tool Systems","description":"","frontmatter":{"title":"Tool Systems","status":"complete"},"headers":[],"relativePath":"research/concepts/tool-systems/index.md","filePath":"research/concepts/tool-systems/index.md"}'),n={name:"research/concepts/tool-systems/index.md"};function l(r,t,p,c,i,d){return o(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="tool-systems" tabindex="-1">Tool Systems <a class="header-anchor" href="#tool-systems" aria-label="Permalink to &quot;Tool Systems&quot;">​</a></h1><p>How coding agents expose capabilities to LLMs, dispatch tool calls, execute them safely, and handle failures. This document synthesizes patterns from 17+ agent implementations.</p><hr><h2 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h2><p>Agents use fundamentally different architectures for structuring their tool systems. The choice shapes everything downstream — extensibility, safety, performance, and cognitive load on the model.</p><h3 id="pattern-1-trait-interface-based" tabindex="-1">Pattern 1: Trait / Interface-Based <a class="header-anchor" href="#pattern-1-trait-interface-based" aria-label="Permalink to &quot;Pattern 1: Trait / Interface-Based&quot;">​</a></h3><p>A statically-typed interface that every tool must implement. The agent dispatches by iterating registered tools and matching by name.</p><p><strong>Go interface (OpenCode):</strong></p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">type</span><span style="color:#F9E2AF;font-style:italic;"> BaseTool</span><span style="color:#CBA6F7;"> interface</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Info</span><span style="color:#9399B2;">()</span><span style="color:#F9E2AF;font-style:italic;"> ToolInfo</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    Run</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">ctx</span><span style="color:#F9E2AF;font-style:italic;"> context</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">Context</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> params</span><span style="color:#F9E2AF;font-style:italic;"> ToolCall</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> (</span><span style="color:#F9E2AF;font-style:italic;">ToolResponse</span><span style="color:#9399B2;">,</span><span style="color:#CBA6F7;"> error</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Rust trait (Codex):</strong></p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> ToolRouter</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> build_tool_call</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> item</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">ResponseItem</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> ToolCall</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        match</span><span style="color:#CDD6F4;"> item </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ResponseItem</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">FunctionCall</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* registry lookup */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            ResponseItem</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">LocalShellCall</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> }</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* shell handler */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            // ...</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Rust trait (Ante):</strong></p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">trait</span><span style="color:#F9E2AF;font-style:italic;"> Tool</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Send</span><span style="color:#94E2D5;"> +</span><span style="color:#F9E2AF;font-style:italic;"> Sync</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> name</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> description</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> input_schema</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Value</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> call</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> input</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Value</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Value</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> ToolError</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Rust trait (Goose — MCP tool router):</strong></p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">async_trait</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> trait</span><span style="color:#F9E2AF;font-style:italic;"> McpClientTrait</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Send</span><span style="color:#94E2D5;"> +</span><span style="color:#F9E2AF;font-style:italic;"> Sync</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> list_tools</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ListToolsResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> call_tool</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">CallToolResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Strengths:</strong> Compile-time safety, clear contract, dependency injection via constructors. Tools are testable units. <strong>Weaknesses:</strong> Adding a tool requires code changes and recompilation. Less accessible to non-core contributors.</p><h3 id="pattern-2-registry-with-dispatch" tabindex="-1">Pattern 2: Registry with Dispatch <a class="header-anchor" href="#pattern-2-registry-with-dispatch" aria-label="Permalink to &quot;Pattern 2: Registry with Dispatch&quot;">​</a></h3><p>A central registry maps tool names to handlers. The agent loop looks up the name and calls the handler. This is the most common pattern.</p><p><strong>OpenCode&#39;s linear dispatch:</strong></p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> _</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> availableTool </span><span style="color:#94E2D5;">:=</span><span style="color:#CBA6F7;"> range</span><span style="color:#CDD6F4;"> a</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">tools </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> availableTool</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Info</span><span style="color:#9399B2;">().</span><span style="color:#CDD6F4;">Name </span><span style="color:#94E2D5;">==</span><span style="color:#CDD6F4;"> toolCall</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Name </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">        tool </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> availableTool</span></span>
<span class="line"><span style="color:#CBA6F7;">        break</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Goose&#39;s namespace-based dispatch:</strong></p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Tools are namespaced as &quot;extensionname__toolname&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> dispatch_tool_call</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> ctx</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> ToolCallContext</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ...</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">extension</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> tool_name</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#89B4FA;font-style:italic;"> resolve_tool</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">name</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // split on &quot;__&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    extension</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">client</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">call_tool</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tool_name</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> arguments</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Gemini CLI&#39;s ToolRegistry:</strong> Built-in tools are statically registered at startup; MCP and custom discovery tools are dynamically added. All tools live in a single registry and appear uniformly to the model.</p><p><strong>Codex&#39;s ToolRouter + ToolRegistry:</strong> Distinguishes tool call types at the enum level (<code>FunctionCall</code>, <code>LocalShellCall</code>, <code>CustomToolCall</code>, <code>ToolSearchCall</code>) before dispatching to the appropriate handler.</p><h3 id="pattern-3-action-observation-model" tabindex="-1">Pattern 3: Action / Observation Model <a class="header-anchor" href="#pattern-3-action-observation-model" aria-label="Permalink to &quot;Pattern 3: Action / Observation Model&quot;">​</a></h3><p>OpenHands takes a unique approach: tools don&#39;t exist as executable objects. They are <em>schemas</em> sent to the LLM. The actual execution flows through a typed pipeline:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>LLM tool_call → response_to_actions() → Action dataclass → Runtime → Observation</span></span></code></pre></div><p>Each tool maps to a specific Action/Observation pair:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Action</th><th>Observation</th></tr></thead><tbody><tr><td><code>execute_bash</code></td><td><code>CmdRunAction</code></td><td><code>CmdOutputObservation</code></td></tr><tr><td><code>str_replace_editor</code></td><td><code>FileEditAction</code></td><td><code>FileEditObservation</code></td></tr><tr><td><code>browser</code></td><td><code>BrowseInteractiveAction</code></td><td><code>BrowserOutputObservation</code></td></tr><tr><td><code>think</code></td><td><code>AgentThinkAction</code></td><td><code>AgentThinkObservation</code></td></tr></tbody></table><p><strong>Why this works:</strong> Actions serialize to an event stream (append-only log), enabling full session replay, security interception, and runtime-agnostic execution. The same Action runs identically on Docker, local, or Kubernetes runtimes.</p><h3 id="pattern-4-mcp-native-tools-as-external-services" tabindex="-1">Pattern 4: MCP-Native (Tools as External Services) <a class="header-anchor" href="#pattern-4-mcp-native-tools-as-external-services" aria-label="Permalink to &quot;Pattern 4: MCP-Native (Tools as External Services)&quot;">​</a></h3><p>Goose&#39;s defining decision: <em>everything is an MCP server</em>. There is no separate &quot;built-in tool&quot; abstraction. The <code>ExtensionManager</code> connects to MCP servers (7 transport types) and presents a unified interface.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Platform extensions  → McpClientTrait (in-process, no transport)</span></span>
<span class="line"><span>Builtin extensions   → McpClientTrait (in-process DuplexStream)</span></span>
<span class="line"><span>Stdio extensions     → McpClientTrait (child process stdin/stdout)</span></span>
<span class="line"><span>StreamableHttp       → McpClientTrait (HTTP)</span></span></code></pre></div><p>Claude Code and Gemini CLI adopt MCP as an <em>extension</em> mechanism alongside built-in tools. OpenHands and OpenCode also support MCP but treat MCP tools as second-class citizens (always requiring permission, prefixed with server name).</p><p><strong>MCP adoption spectrum:</strong></p><table tabindex="0"><thead><tr><th>Agent</th><th>MCP Role</th></tr></thead><tbody><tr><td>Goose</td><td><strong>Core architecture</strong> — everything is MCP</td></tr><tr><td>Claude Code</td><td>Extension mechanism + can serve as MCP server</td></tr><tr><td>Gemini CLI</td><td>Extension mechanism alongside built-in tools</td></tr><tr><td>Codex</td><td>Both client and server; MCP tools are first-class <code>FunctionCall</code></td></tr><tr><td>OpenCode</td><td>Extension; tools prefixed <code>{server}_{tool}</code>, always need permission</td></tr><tr><td>OpenHands</td><td>Extension via microagents; first-class in action pipeline</td></tr><tr><td>Pi</td><td>No built-in MCP; community package <code>pi-mcp-adapter</code></td></tr><tr><td>Ante</td><td>Custom Rust MCP SDK; bidirectional support</td></tr><tr><td>mini-SWE-agent</td><td>None</td></tr></tbody></table><h3 id="pattern-5-no-tools-at-all-bash-only" tabindex="-1">Pattern 5: No Tools At All (Bash-Only) <a class="header-anchor" href="#pattern-5-no-tools-at-all-bash-only" aria-label="Permalink to &quot;Pattern 5: No Tools At All (Bash-Only)&quot;">​</a></h3><p>mini-SWE-agent&#39;s radical position: one tool — bash. Everything else (file editing, search, navigation, git) is done through shell commands the LLM already knows.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">BASH_TOOL </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;type&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;function&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;function&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;name&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;bash&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;description&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Execute a bash command&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;parameters&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;properties&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">                &quot;command&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#A6E3A1;"> &quot;type&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">            },</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;required&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;command&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Why it works:</strong> Modern LLMs know <code>grep</code>, <code>sed</code>, <code>find</code>, <code>git</code>, and hundreds of other tools from training data. Custom agent tools are abstractions <em>on top of</em> things the LLM already knows. The SWE-agent team&#39;s own data shows the gap between custom tools and bash-only shrank dramatically as models improved from GPT-4 to Claude 3.5+.</p><p><strong>Trade-offs:</strong> Zero setup in sandboxes, universal model compatibility. But: no safety guardrails beyond the sandbox, higher token cost per operation, and the model must know bash idioms for every operation.</p><h3 id="pattern-6-edit-format-system-prompt-based-tools" tabindex="-1">Pattern 6: Edit Format System (Prompt-Based Tools) <a class="header-anchor" href="#pattern-6-edit-format-system-prompt-based-tools" aria-label="Permalink to &quot;Pattern 6: Edit Format System (Prompt-Based Tools)&quot;">​</a></h3><p>Aider doesn&#39;t use function calling at all. Its &quot;tools&quot; are <em>edit formats</em> — structured text protocols for expressing code changes:</p><table tabindex="0"><thead><tr><th>Format</th><th>How It Works</th><th>Best For</th></tr></thead><tbody><tr><td><code>whole</code></td><td>LLM returns entire file</td><td>Weak models, small files</td></tr><tr><td><code>diff</code></td><td>SEARCH/REPLACE blocks</td><td>Most capable models</td></tr><tr><td><code>diff-fenced</code></td><td>Diff with filename inside fence</td><td>Gemini models specifically</td></tr><tr><td><code>udiff</code></td><td>Unified diff format</td><td>GPT-4 Turbo (anti-laziness)</td></tr><tr><td><code>architect</code></td><td>Two-model pipeline: reason then edit</td><td>Reasoning models (o1, o3, R1)</td></tr><tr><td><code>whole-func</code> / <code>diff-func</code></td><td>JSON function calling</td><td><strong>Worse</strong> than plain text (historical)</td></tr></tbody></table><p><strong>Key insight from Aider&#39;s benchmarks:</strong> Function-call formats (<code>whole-func</code>, <code>diff-func</code>) performed <em>worse</em> than plain text. The cognitive overhead of producing valid JSON hurt both code quality and format adherence. This finding shaped industry thinking about LLM tool interfaces.</p><h3 id="pattern-comparison" tabindex="-1">Pattern Comparison <a class="header-anchor" href="#pattern-comparison" aria-label="Permalink to &quot;Pattern Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pattern</th><th>Extensibility</th><th>Safety</th><th>Cognitive Load</th><th>Setup Cost</th></tr></thead><tbody><tr><td>Trait/interface</td><td>Moderate (code changes)</td><td>Compile-time checks</td><td>Low (typed)</td><td>High</td></tr><tr><td>Registry</td><td>High (dynamic registration)</td><td>Runtime validation</td><td>Low</td><td>Medium</td></tr><tr><td>Action/observation</td><td>High (new Action types)</td><td>Event-stream audit</td><td>Medium</td><td>High</td></tr><tr><td>MCP-native</td><td>Very high (any MCP server)</td><td>Depends on inspectors</td><td>Medium</td><td>Low</td></tr><tr><td>Bash-only</td><td>Infinite (any CLI tool)</td><td>None (sandbox only)</td><td>High for model</td><td>Zero</td></tr><tr><td>Edit formats</td><td>None (fixed formats)</td><td>N/A (no execution)</td><td>Varies by format</td><td>Zero</td></tr></tbody></table><hr><h2 id="json-schema-—-how-tools-describe-themselves-to-llms" tabindex="-1">JSON Schema — How Tools Describe Themselves to LLMs <a class="header-anchor" href="#json-schema-—-how-tools-describe-themselves-to-llms" aria-label="Permalink to &quot;JSON Schema — How Tools Describe Themselves to LLMs&quot;">​</a></h2><p>The schema sent to the model is the <em>entire interface</em> between agent and LLM. Schema design directly affects tool-calling reliability.</p><h3 id="standard-formats" tabindex="-1">Standard Formats <a class="header-anchor" href="#standard-formats" aria-label="Permalink to &quot;Standard Formats&quot;">​</a></h3><p><strong>OpenAI function calling (most agents):</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;function&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">function</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;execute_bash&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Execute a bash command in the terminal...&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">parameters</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;object&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">command</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">        &quot;</span><span style="color:#89B4FA;">timeout</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;integer&quot;</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">      },</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">required</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;command&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Used by: OpenHands, OpenCode, mini-SWE-agent, Gemini CLI, ForgeCode, Capy, TongAgents.</p><p><strong>Anthropic tool_use format (Claude Code):</strong> Tools are defined in the API request and the model returns structured <code>tool_use</code> blocks. Claude Code uses Anthropic&#39;s native tool-use protocol — not prompt injection. The model returns blocks like:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;tool_use&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;toolu_01A...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Edit&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">input</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">file_path</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">old_str</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;...&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">new_str</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;...&quot;</span><span style="color:#9399B2;"> }</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p><strong>MCP tool definitions (Goose, Codex as MCP server):</strong></p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;codex&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">description</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Run a Codex session&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">  &quot;</span><span style="color:#89B4FA;">inputSchema</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">properties</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">prompt</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">approval-policy</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">enum</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;untrusted&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;on-failure&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;on-request&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;never&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> },</span></span>
<span class="line"><span style="color:#9399B2;">      &quot;</span><span style="color:#89B4FA;">sandbox</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> {</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">enum</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;read-only&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;workspace-write&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;danger-full-access&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">  }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Schema derivation from types (Goose):</strong></p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> schema</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">T</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> JsonSchema</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> JsonObject</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;">    serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">to_value</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">schema_for!</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">T</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;schema&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_object</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;object&quot;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Goose derives JSON Schema directly from Rust struct definitions using <code>schemars::JsonSchema</code>, eliminating manual schema maintenance.</p><h3 id="schema-engineering-—-tricks-that-matter" tabindex="-1">Schema Engineering — Tricks That Matter <a class="header-anchor" href="#schema-engineering-—-tricks-that-matter" aria-label="Permalink to &quot;Schema Engineering — Tricks That Matter&quot;">​</a></h3><p><strong>ForgeCode&#39;s field ordering insight:</strong> Putting <code>required</code> before <code>properties</code> in the JSON Schema improves model compliance. This is a training-data alignment trick — models have seen more schemas in that order.</p><p><strong>ForgeCode&#39;s naming alignment:</strong> Using <code>old_string</code>/<code>new_string</code> instead of creative names aligns with the edit tool naming conventions most common in training data. Training-data-aligned naming reduces tool-calling errors.</p><p><strong>ForgeCode&#39;s flat schemas:</strong> Nested object schemas cause more errors than flat ones. Flattening parameters into a single level of properties reduces model confusion.</p><p><strong>OpenHands&#39; description length adaptation:</strong> Different models have different tool-description token limits. OpenHands maintains two variants:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> create_cmd_run_tool</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">cwd</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> short</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> bool</span><span style="color:#94E2D5;"> =</span><span style="color:#CBA6F7;"> False</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> short</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        description </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> CMD_RUN_TOOL_SHORT_DESCRIPTION  </span><span style="color:#6C7086;font-style:italic;"># &lt; 1024 tokens</span></span>
<span class="line"><span style="color:#CBA6F7;">    else</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        description </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> CMD_RUN_TOOL_DESCRIPTION         </span><span style="color:#6C7086;font-style:italic;"># ~2000+ tokens</span></span></code></pre></div><p>Short descriptions are used for GPT-4, o1, o3, o4 families.</p><p><strong>Goose&#39;s argument coercion:</strong> Rather than failing on type mismatches, Goose coerces LLM arguments to match schemas. This handles the common case where LLMs send <code>&quot;42&quot;</code> instead of <code>42</code>.</p><p><strong>Discriminated union (OpenHands&#39; str_replace_editor):</strong> One tool with a <code>command</code> enum dispatches to different operations:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#A6E3A1;">&quot;command&quot;</span><span style="color:#CDD6F4;">: </span><span style="color:#9399B2;">{</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">type</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;string&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">enum</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;view&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;create&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;str_replace&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;insert&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;undo_edit&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>This reduces the number of tools the model must track while enabling 5 distinct operations through a single interface.</p><p><strong>Claude Code&#39;s MCP Tool Search:</strong> When MCP tools exceed 10% of context window, tools are deferred rather than preloaded. The model uses a search tool to discover relevant MCP tools on demand — lazy-loading for tool schemas.</p><h3 id="schema-design-impact-on-performance" tabindex="-1">Schema Design Impact on Performance <a class="header-anchor" href="#schema-design-impact-on-performance" aria-label="Permalink to &quot;Schema Design Impact on Performance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Effect</th><th>Source</th></tr></thead><tbody><tr><td>Field ordering (<code>required</code> first)</td><td>Improved compliance</td><td>ForgeCode</td></tr><tr><td>Flat vs nested schemas</td><td>Fewer argument errors</td><td>ForgeCode</td></tr><tr><td>Training-aligned naming</td><td>Lower error rate</td><td>ForgeCode</td></tr><tr><td>Short descriptions for constrained models</td><td>Fits within token limits</td><td>OpenHands</td></tr><tr><td>Argument coercion (string→int)</td><td>Fewer type mismatches</td><td>Goose</td></tr><tr><td>Discriminated unions (multi-command tools)</td><td>Fewer tools to track</td><td>OpenHands</td></tr><tr><td>Lazy tool loading (Tool Search)</td><td>Preserves context budget</td><td>Claude Code</td></tr><tr><td>Plain text &gt; JSON function calling</td><td>Better code quality</td><td>Aider benchmarks</td></tr></tbody></table><hr><h2 id="execution-models" tabindex="-1">Execution Models <a class="header-anchor" href="#execution-models" aria-label="Permalink to &quot;Execution Models&quot;">​</a></h2><p>How tool calls actually run — from hermetically sealed sandboxes to unrestricted shell access.</p><h3 id="sandboxed-execution" tabindex="-1">Sandboxed Execution <a class="header-anchor" href="#sandboxed-execution" aria-label="Permalink to &quot;Sandboxed Execution&quot;">​</a></h3><p><strong>Codex — 3-Layer Linux Sandbox (most sophisticated):</strong></p><table tabindex="0"><thead><tr><th>Layer</th><th>Mechanism</th><th>What It Does</th></tr></thead><tbody><tr><td>1. Bubblewrap</td><td>Mount namespaces</td><td>Filesystem read-only by default, explicit writable dirs, PID/user/network isolation</td></tr><tr><td>2. seccomp</td><td>Syscall filtering</td><td>Blocks ptrace, io_uring, network syscalls; allows only AF_UNIX sockets</td></tr><tr><td>3. Landlock</td><td>LSM filesystem rules</td><td>Legacy fallback; path-based read/write restrictions</td></tr></tbody></table><p>Plus: macOS Seatbelt (<code>sandbox-exec -p</code>), Windows ACL Deny ACEs + firewall rules + restricted tokens + alternate desktops. Cross-platform coverage is unmatched.</p><p>Codex also implements proxy routing — a TCP→UDS→TCP bridge that allows sandboxed processes to reach only configured proxy endpoints while maintaining complete network isolation.</p><p><strong>OpenHands — Docker Container:</strong> Every Action executes inside a Docker container via <code>EventStreamRuntime</code>. The container runs an <code>ActionExecutionServer</code> that receives Actions over HTTP. Jupyter kernel, browser (Playwright), and shell all run inside the container. This provides strong isolation but with higher startup cost.</p><p><strong>Gemini CLI — Multi-Tier Sandboxing:</strong> Supports multiple sandbox backends depending on platform:</p><ul><li>macOS: Seatbelt profiles (similar to Codex)</li><li>Linux: Docker containers</li><li>Configurable per-tool: <code>run_shell_command</code> is always sandboxed; file tools may or may not be depending on configuration</li></ul><p><strong>Capy — Full VM Per Task:</strong> The most heavyweight approach: each task runs in its own Ubuntu VM with sudo access. Complete isolation from other tasks/users. Network access for package managers only.</p><h3 id="direct-execution-with-permission-gates" tabindex="-1">Direct Execution (with Permission Gates) <a class="header-anchor" href="#direct-execution-with-permission-gates" aria-label="Permalink to &quot;Direct Execution (with Permission Gates)&quot;">​</a></h3><p><strong>Claude Code — 5 Permission Modes:</strong></p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th></tr></thead><tbody><tr><td><code>default</code></td><td>Prompts for first use of each tool</td></tr><tr><td><code>acceptEdits</code></td><td>Auto-accepts file edits; asks for Bash</td></tr><tr><td><code>plan</code></td><td>Read-only — analyze but not modify</td></tr><tr><td><code>dontAsk</code></td><td>Auto-denies unless pre-approved</td></tr><tr><td><code>bypassPermissions</code></td><td>Skips all prompts (dangerous)</td></tr></tbody></table><p>Permission rules use glob patterns: <code>Bash(npm run *)</code>, <code>Read(src/**)</code>, <code>WebFetch(domain:example.com)</code>. Evaluation order: <strong>deny → ask → allow</strong>, first match wins. Managed settings cannot be overridden.</p><p><strong>OpenCode — Permission Service:</strong> Tools marked as requiring permission block the agent loop until the user responds. Options: allow once, allow for session, deny, or auto-approve (non-interactive mode). Bash tool has banned commands (<code>curl</code>, <code>wget</code>, <code>nc</code>) and safe read-only command whitelist.</p><p><strong>Warp — Category-Based:</strong> Read-only operations (read file, list dir, search) require no permission. Write operations (write, edit, delete, move) and Computer Use require explicit permission. Tool invocation follows a priority: built-in files → shell → LSP → web → MCP → Computer Use (last resort).</p><h3 id="stateless-subprocess" tabindex="-1">Stateless Subprocess <a class="header-anchor" href="#stateless-subprocess" aria-label="Permalink to &quot;Stateless Subprocess&quot;">​</a></h3><p><strong>mini-SWE-agent — subprocess.run Per Action:</strong> Every command runs in a fresh subprocess. Directory and environment changes do NOT persist:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Each action is a new subprocess</span></span>
<span class="line"><span style="color:#CDD6F4;">subprocess</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">command</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> shell</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> capture_output</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> timeout</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">timeout</span><span style="color:#9399B2;">)</span></span></code></pre></div><p>The system prompt teaches the model to prefix commands with <code>cd /path &amp;&amp; ...</code> to work around non-persistence. Environment variables configured once via YAML (<code>PAGER=cat</code>, <code>PIP_PROGRESS_BAR=off</code>) to prevent interactive hangs.</p><h3 id="persistent-shell-session" tabindex="-1">Persistent Shell Session <a class="header-anchor" href="#persistent-shell-session" aria-label="Permalink to &quot;Persistent Shell Session&quot;">​</a></h3><p>Most production agents keep a bash session alive across tool calls:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Shell Persistence</th><th>Env Vars Persist?</th><th>CWD Persists?</th></tr></thead><tbody><tr><td>OpenCode</td><td>Persistent shell (<code>GetPersistentShell()</code>)</td><td>Yes</td><td>Yes</td></tr><tr><td>Claude Code</td><td>Separate process per command</td><td>No</td><td>Yes</td></tr><tr><td>Codex</td><td>Sandboxed process per command</td><td>Per-sandbox</td><td>Per-sandbox</td></tr><tr><td>Gemini CLI</td><td>Persistent</td><td>Yes</td><td>Yes</td></tr><tr><td>OpenHands</td><td>Persistent within Docker container</td><td>Yes</td><td>Yes</td></tr><tr><td>mini-SWE-agent</td><td>New subprocess each time</td><td>No</td><td>No</td></tr><tr><td>Pi</td><td>Full shell access, no persistence specified</td><td>Unknown</td><td>Unknown</td></tr></tbody></table><h3 id="parallel-tool-execution" tabindex="-1">Parallel Tool Execution <a class="header-anchor" href="#parallel-tool-execution" aria-label="Permalink to &quot;Parallel Tool Execution&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Parallel Tool Calls?</th><th>How?</th></tr></thead><tbody><tr><td>OpenHands</td><td>Yes</td><td>Multiple tool_calls in one LLM response; all processed, results returned together</td></tr><tr><td>Claude Code</td><td>Yes</td><td>Multiple tool_use blocks in one response</td></tr><tr><td>Codex</td><td>Yes</td><td>Multiple FunctionCall items in one response</td></tr><tr><td>Goose</td><td>Yes</td><td>Async dispatch via tokio</td></tr><tr><td>OpenCode</td><td><strong>No</strong></td><td>Sequential execution, one tool at a time</td></tr><tr><td>Gemini CLI</td><td>Yes</td><td>Multiple tool calls supported</td></tr><tr><td>mini-SWE-agent</td><td><strong>No</strong></td><td>Single command per step enforced by system prompt</td></tr><tr><td>Aider</td><td>N/A</td><td>No function calling; sequential edit application</td></tr></tbody></table><h3 id="permission-safety-comparison" tabindex="-1">Permission &amp; Safety Comparison <a class="header-anchor" href="#permission-safety-comparison" aria-label="Permalink to &quot;Permission &amp; Safety Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Sandbox</th><th>Permission Model</th><th>Banned Commands</th><th>Network Control</th></tr></thead><tbody><tr><td>Codex</td><td>3-layer OS sandbox</td><td>4-level approval policy + execution policy engine</td><td>Yes (policy-based allowlist)</td><td>seccomp + proxy routing</td></tr><tr><td>OpenHands</td><td>Docker container</td><td>SecurityAnalyzer (rule or LLM-based) + confirmation</td><td>No explicit list</td><td>Container network</td></tr><tr><td>Claude Code</td><td>None (direct)</td><td>5 permission modes + glob rules</td><td>No explicit list</td><td>Permission required</td></tr><tr><td>Gemini CLI</td><td>Multi-tier (Seatbelt/Docker)</td><td>Confirmation model (read-only vs mutating)</td><td>No explicit list</td><td>Sandbox-dependent</td></tr><tr><td>OpenCode</td><td>None (direct)</td><td>Permission service + command filtering</td><td>Yes (<code>curl</code>, <code>wget</code>, <code>nc</code>, etc.)</td><td>Banned commands</td></tr><tr><td>Goose</td><td>None (direct)</td><td>4-tier inspection pipeline</td><td>SecurityInspector patterns</td><td>No</td></tr><tr><td>Pi</td><td>None (direct)</td><td>None by default; extensions can add</td><td>None</td><td>None</td></tr><tr><td>mini-SWE-agent</td><td>External (Docker in benchmarks)</td><td>None</td><td>None</td><td>Sandbox-dependent</td></tr><tr><td>Capy</td><td>Full Ubuntu VM</td><td>Hard agent-tool boundaries (Captain can&#39;t write; Build can&#39;t ask user)</td><td>Platform-enforced</td><td>VM network</td></tr><tr><td>Junie CLI</td><td>Project scope enforcement</td><td>4-level permission system (L0-L3)</td><td>Security pattern filtering</td><td>L3 required</td></tr><tr><td>ForgeCode</td><td>None</td><td>None (user&#39;s native shell)</td><td>None</td><td>None</td></tr></tbody></table><p><strong>Goose&#39;s 4-tier inspection pipeline</strong> deserves special mention:</p><ol><li><strong>SecurityInspector</strong> — Pattern-matches dangerous commands</li><li><strong>AdversaryInspector</strong> — Detects prompt injection in tool arguments</li><li><strong>PermissionInspector</strong> — Per-tool rules (Autonomous/Manual/Smart/Chat-Only)</li><li><strong>RepetitionInspector</strong> — Detects infinite retry loops</li></ol><p>Every tool call passes through all four inspectors, even in autonomous mode.</p><p><strong>Codex&#39;s execution policy engine</strong> is the most granular:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> enum</span><span style="color:#F9E2AF;font-style:italic;"> Decision</span><span style="color:#9399B2;"> {</span><span style="color:#F9E2AF;font-style:italic;"> Allow</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Prompt</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Forbidden</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>Rules match by program name + argument prefix patterns. A shell command parser (84KB, the largest single file in the codebase) decomposes complex shell expressions into individual invocations for per-command policy evaluation. Special argument types (<code>ARG_RFILES</code>, <code>ARG_WFILE</code>, <code>ARG_SED_COMMAND</code>) constrain what commands can do.</p><hr><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><p>How agents deal with tool failures — from simple error messages to sophisticated correction loops.</p><h3 id="tool-validation-failures" tabindex="-1">Tool Validation Failures <a class="header-anchor" href="#tool-validation-failures" aria-label="Permalink to &quot;Tool Validation Failures&quot;">​</a></h3><p>Most agents return errors as tool results rather than crashing:</p><p><strong>OpenCode:</strong> Go errors reserved for infrastructure failures; tool errors returned as <code>ToolResponse{IsError: true}</code>:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#CDD6F4;"> tool </span><span style="color:#94E2D5;">==</span><span style="color:#F38BA8;"> nil</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    toolResults</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">i</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;font-style:italic;"> message</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">ToolResult</span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">        Content</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> fmt</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Sprintf</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Tool not found: %s&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> toolCall</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Name</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#CDD6F4;">        IsError</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#CBA6F7;">    continue</span><span style="color:#6C7086;font-style:italic;">  // Not fatal — reported back to LLM</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>OpenHands:</strong> <code>str_replace_editor</code> fails cleanly on ambiguous matches — if <code>old_str</code> matches zero or multiple locations, a descriptive error observation is returned. The model can then refine its search string.</p><p><strong>Ante:</strong> Typed Rust errors (<code>InvalidArgs</code>, <code>Execution</code>, <code>Timeout</code>) via <code>Result&lt;Value, ToolError&gt;</code>. Compile-time type safety catches schema violations early through <code>serde::Deserialize</code>.</p><p><strong>Aider&#39;s fuzzy matching:</strong> When the SEARCH block doesn&#39;t match exactly, Aider tries progressively looser matching:</p><ol><li>Exact match</li><li>Strip trailing whitespace</li><li>Ignore blank lines</li><li>Normalized whitespace matching</li></ol><p>This is a rare example of the tool system <em>repairing</em> model output before failing.</p><h3 id="timeout-handling" tabindex="-1">Timeout Handling <a class="header-anchor" href="#timeout-handling" aria-label="Permalink to &quot;Timeout Handling&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Default Timeout</th><th>Max Timeout</th><th>Behavior on Timeout</th></tr></thead><tbody><tr><td>OpenCode</td><td>60 seconds</td><td>10 minutes</td><td>Kill process</td></tr><tr><td>OpenHands</td><td>Configurable per-call</td><td>Per <code>timeout</code> param</td><td>Force terminate</td></tr><tr><td>Codex</td><td>Configurable</td><td>Per sandbox policy</td><td>Kill + report</td></tr><tr><td>mini-SWE-agent</td><td>Configurable</td><td>Per config</td><td><code>subprocess.run</code> timeout</td></tr><tr><td>Ante</td><td>30 seconds</td><td>Configurable</td><td><code>ToolError::Timeout</code></td></tr><tr><td>ForgeCode</td><td>300 seconds</td><td><code>FORGE_TOOL_TIMEOUT</code></td><td>Kill hung commands</td></tr><tr><td>Goose</td><td>Per-extension configurable</td><td>300s default for stdio</td><td>MCP timeout</td></tr></tbody></table><h3 id="output-truncation" tabindex="-1">Output Truncation <a class="header-anchor" href="#output-truncation" aria-label="Permalink to &quot;Output Truncation&quot;">​</a></h3><p>Long outputs consume context budget. Agents handle this differently:</p><p><strong>OpenCode</strong> — Keep first and last halves (30,000 char limit):</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#89B4FA;font-style:italic;"> truncateOutput</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">content</span><span style="color:#CBA6F7;"> string</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> string</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    halfLength </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> MaxOutputLength </span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;"> 2</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> fmt</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Sprintf</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;%s</span><span style="color:#F5C2E7;">\\n\\n</span><span style="color:#A6E3A1;">... [%d lines truncated] ...</span><span style="color:#F5C2E7;">\\n\\n</span><span style="color:#A6E3A1;">%s&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        content</span><span style="color:#9399B2;">[:</span><span style="color:#CDD6F4;">halfLength</span><span style="color:#9399B2;">],</span><span style="color:#CDD6F4;"> truncatedLinesCount</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> content</span><span style="color:#9399B2;">[</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">content</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;">halfLength</span><span style="color:#9399B2;">:])</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>mini-SWE-agent</strong> — Head + tail with explicit elision (10,000 char limit):</p><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#94E2D5;">&lt;</span><span style="color:#89B4FA;">output_head</span><span style="color:#94E2D5;">&gt;</span><span style="color:#CDD6F4;">{{ output.output[:5000] }}</span><span style="color:#94E2D5;">&lt;/</span><span style="color:#89B4FA;">output_head</span><span style="color:#94E2D5;">&gt;</span></span>
<span class="line"><span style="color:#94E2D5;">&lt;</span><span style="color:#89B4FA;">elided_chars</span><span style="color:#94E2D5;">&gt;</span><span style="color:#CDD6F4;">{{ elided_chars }} characters elided</span><span style="color:#94E2D5;">&lt;/</span><span style="color:#89B4FA;">elided_chars</span><span style="color:#94E2D5;">&gt;</span></span>
<span class="line"><span style="color:#94E2D5;">&lt;</span><span style="color:#89B4FA;">output_tail</span><span style="color:#94E2D5;">&gt;</span><span style="color:#CDD6F4;">{{ output.output[-5000:] }}</span><span style="color:#94E2D5;">&lt;/</span><span style="color:#89B4FA;">output_tail</span><span style="color:#94E2D5;">&gt;</span></span></code></pre></div><p><strong>ForgeCode</strong> — Explicit truncation signals in plain text (not just metadata), because some models miss metadata fields.</p><h3 id="retry-strategies" tabindex="-1">Retry Strategies <a class="header-anchor" href="#retry-strategies" aria-label="Permalink to &quot;Retry Strategies&quot;">​</a></h3><p><strong>Codex — Sandbox escalation retry:</strong></p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">match</span><span style="color:#CDD6F4;"> result </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Err</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">SandboxErr</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Denied</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;"> })</span><span style="color:#CBA6F7;"> if</span><span style="color:#CDD6F4;"> tool</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">escalate_on_failure</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Request user approval to retry without sandbox</span></span>
<span class="line"><span style="color:#F38BA8;">        Self</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">run_attempt</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tool</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> req</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> escalated_sandbox</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ..</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>If a command fails due to sandbox restrictions, Codex can request escalation and retry with relaxed permissions.</p><p><strong>ForgeCode — Tool-call correction layer (highest-impact innovation):</strong> A programmatic interception layer validates and repairs LLM tool calls <em>before</em> execution. Catches three failure classes:</p><ol><li><strong>Wrong tool selected</strong> — redirects to correct tool</li><li><strong>Correct tool, wrong arguments</strong> — pattern-matches common errors and auto-corrects</li><li><strong>Correct call, wrong sequencing</strong> — enforces ordering constraints</li></ol><p>Plus a <code>max_tool_failure_per_turn: 3</code> limit to prevent infinite retry loops. Per-tool micro-evaluations run in CI/CD to gate releases.</p><p><strong>mini-SWE-agent — Format error correction:</strong></p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">format_error_template</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">  Format error:</span></span>
<span class="line"><span style="color:#A6E3A1;">  &lt;error&gt;{{error}}&lt;/error&gt;</span></span>
<span class="line"><span style="color:#A6E3A1;">  Please always provide EXACTLY ONE action in triple backticks.</span></span></code></pre></div><p>Format errors (<code>FormatError</code> exception) add a corrective message to the conversation and let the model retry on the next step.</p><p><strong>Goose — RepetitionInspector:</strong> Detects tools called repeatedly without progress. Prevents infinite loops where the agent keeps retrying a failing tool. Returns <code>DECLINED_RESPONSE</code> to force the LLM to try an alternative approach.</p><h3 id="error-feedback-loops" tabindex="-1">Error Feedback Loops <a class="header-anchor" href="#error-feedback-loops" aria-label="Permalink to &quot;Error Feedback Loops&quot;">​</a></h3><p><strong>OpenCode + OpenHands — LSP integration for immediate feedback:</strong> After file edits, both agents wait for LSP diagnostics and append type errors/warnings to the tool response. The model gets immediate feedback on its changes without needing a separate build/lint step:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// After edit, wait briefly for LSP</span></span>
<span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#89B4FA;font-style:italic;"> waitForLspDiagnostics</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">ctx</span><span style="color:#F9E2AF;font-style:italic;"> context</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">Context</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> filePath</span><span style="color:#CBA6F7;"> string</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> lspClients</span><span style="color:#CBA6F7;"> map</span><span style="color:#9399B2;">[</span><span style="color:#CBA6F7;">string</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">*</span><span style="color:#F9E2AF;font-style:italic;">lsp</span><span style="color:#9399B2;">.</span><span style="color:#F9E2AF;font-style:italic;">Client</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Warp — Active AI error monitoring:</strong> Proactively monitors command exit codes and error output, suggests one-click fixes for common errors using pattern matching. This is the only agent where error handling is a <em>proactive</em> capability rather than reactive.</p><p><strong>Droid — GitHub Actions repair:</strong> The <code>github_action_repair</code> tool automatically analyzes CI failures, identifies root causes, and creates repair PRs. Error handling elevated to a first-class workflow.</p><p><strong>Junie CLI — Structured test result parsing:</strong> Extracts test name, file, line, status, error type, and expected/actual values from test output across 13+ test frameworks in 8 languages. Build output is parsed for error locations. This structured error information gives the model precise targets for fixes.</p><h3 id="error-handling-comparison" tabindex="-1">Error Handling Comparison <a class="header-anchor" href="#error-handling-comparison" aria-label="Permalink to &quot;Error Handling Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Validation Errors</th><th>Timeout</th><th>Retry Strategy</th><th>Feedback Loop</th></tr></thead><tbody><tr><td>Codex</td><td>Error observation</td><td>Kill process</td><td>Sandbox escalation</td><td>Policy amendment</td></tr><tr><td>OpenHands</td><td>Descriptive error obs</td><td>Force terminate</td><td>Model retries naturally</td><td>LSP diagnostics</td></tr><tr><td>Claude Code</td><td>Error in tool result</td><td>Process kill</td><td>Model retries</td><td>LSP via plugin</td></tr><tr><td>OpenCode</td><td><code>IsError: true</code> response</td><td>Kill (60s default)</td><td>Model retries</td><td>LSP diagnostics</td></tr><tr><td>Goose</td><td>Inspection pipeline</td><td>Per-extension timeout</td><td>RepetitionInspector</td><td>—</td></tr><tr><td>Gemini CLI</td><td>Error in result</td><td>Sandbox-dependent</td><td>Model retries</td><td>—</td></tr><tr><td>mini-SWE-agent</td><td>FormatError + retry</td><td>subprocess timeout</td><td>Corrective message</td><td>—</td></tr><tr><td>Aider</td><td>Fuzzy match fallback</td><td>N/A</td><td>Progressive matching</td><td>—</td></tr><tr><td>ForgeCode</td><td>Correction layer</td><td>300s kill</td><td>Auto-correct + 3-failure limit</td><td>Micro-evaluations</td></tr><tr><td>Pi</td><td>Extension-dependent</td><td>Extension-dependent</td><td>Extension-dependent</td><td>Extension-dependent</td></tr><tr><td>Warp</td><td>Active AI monitoring</td><td>—</td><td>One-click fix suggestions</td><td>Proactive error detection</td></tr></tbody></table><hr><h2 id="tools-projects" tabindex="-1">Tools &amp; Projects <a class="header-anchor" href="#tools-projects" aria-label="Permalink to &quot;Tools &amp; Projects&quot;">​</a></h2><p>A curated map of the tools, libraries, and protocols that power the tool layer of modern coding agents. For deeper coverage, see the <a href="./../../.copilot/session-state/d0354d87-4da1-4c93-a043-006f84879a18/files/tool-systems-tools.html">full research compendium</a>.</p><h3 id="mcp-protocol-sdks" tabindex="-1">MCP Protocol &amp; SDKs <a class="header-anchor" href="#mcp-protocol-sdks" aria-label="Permalink to &quot;MCP Protocol &amp; SDKs&quot;">​</a></h3><ul><li><strong>Model Context Protocol (MCP)</strong> — Open protocol (Linux Foundation / Anthropic) standardizing how LLM apps connect to external tools via JSON-RPC 2.0. <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">https://modelcontextprotocol.io</a>. Eliminates the N×M integration problem: one server works with every MCP-compatible agent.</li><li><strong>TypeScript SDK</strong> — <code>@modelcontextprotocol/server</code> / <code>client</code>. Node, Bun, Deno. v1 stable; v2 pre-alpha. <a href="https://github.com/modelcontextprotocol/typescript-sdk" target="_blank" rel="noreferrer">https://github.com/modelcontextprotocol/typescript-sdk</a></li><li><strong>Python SDK</strong> — <code>pip install &quot;mcp[cli]&quot;</code>. High-level <code>FastMCP</code> decorator API for defining tools, resources, and prompts in a few lines. <a href="https://github.com/modelcontextprotocol/python-sdk" target="_blank" rel="noreferrer">https://github.com/modelcontextprotocol/python-sdk</a></li><li><strong>Other official SDKs</strong> — Go, Rust, Java, Kotlin, C#, Swift, Ruby, PHP — all under <a href="https://github.com/modelcontextprotocol" target="_blank" rel="noreferrer">https://github.com/modelcontextprotocol</a></li><li><strong>MCP Server Registry</strong> — Browsable catalog of published servers (filesystem, Git, fetch, memory, Slack, Sentry, etc.). <a href="https://registry.modelcontextprotocol.io" target="_blank" rel="noreferrer">https://registry.modelcontextprotocol.io</a></li></ul><h3 id="sandboxing-isolation" tabindex="-1">Sandboxing &amp; Isolation <a class="header-anchor" href="#sandboxing-isolation" aria-label="Permalink to &quot;Sandboxing &amp; Isolation&quot;">​</a></h3><ul><li><strong>bubblewrap (bwrap)</strong> — Lightweight, unprivileged Linux sandboxing via namespaces. C, nearly zero deps. Used by Flatpak. Ideal low-overhead primitive for custom agent sandboxes. <a href="https://github.com/containers/bubblewrap" target="_blank" rel="noreferrer">https://github.com/containers/bubblewrap</a></li><li><strong>Landlock LSM</strong> — Kernel module (Linux 5.13+) letting unprivileged processes restrict their own filesystem access at runtime. No container overhead — just syscalls. <a href="https://landlock.io" target="_blank" rel="noreferrer">https://landlock.io</a></li><li><strong>seccomp-bpf</strong> — Kernel feature filtering syscalls with BPF programs. Foundational layer used by Docker, bubblewrap, Chrome. Prevents dangerous syscalls (<code>mount</code>, <code>ptrace</code>). Linux kernel built-in.</li><li><strong>gVisor</strong> — Application kernel (Go) that re-implements Linux syscalls in userspace. OCI-compatible (<code>runsc</code>). Strongest isolation for containers; used by Google Cloud Run. ~5–15 % CPU overhead. <a href="https://github.com/google/gvisor" target="_blank" rel="noreferrer">https://github.com/google/gvisor</a></li><li><strong>E2B</strong> — Cloud sandboxes purpose-built for AI code execution. Instant creation via API, Python/JS SDKs. Self-hostable on GCP. <a href="https://e2b.dev" target="_blank" rel="noreferrer">https://e2b.dev</a></li><li><strong>Daytona</strong> — AGPL-3.0 sandbox infra with sub-90 ms creation, built-in LSP, and unlimited persistence. Python/TS/Go SDKs. <a href="https://daytona.io" target="_blank" rel="noreferrer">https://daytona.io</a></li></ul><table tabindex="0"><thead><tr><th>Solution</th><th>Isolation</th><th>Overhead</th><th>Root?</th><th>Best For</th></tr></thead><tbody><tr><td>seccomp</td><td>Syscall filter</td><td>Negligible</td><td>No</td><td>Restricting dangerous syscalls</td></tr><tr><td>Landlock</td><td>Filesystem LSM</td><td>Negligible</td><td>No</td><td>Runtime filesystem restrictions</td></tr><tr><td>bubblewrap</td><td>Namespace-based</td><td>Low</td><td>No</td><td>Custom sandbox building blocks</td></tr><tr><td>gVisor</td><td>Userspace kernel</td><td>Medium (~5–15 %)</td><td>Yes</td><td>Untrusted code in containers</td></tr><tr><td>Docker</td><td>Container (ns + cgroups)</td><td>Low–Medium</td><td>Yes (daemon)</td><td>Standard agent sandboxing</td></tr><tr><td>E2B</td><td>Cloud sandbox</td><td>Medium (network)</td><td>N/A (managed)</td><td>SaaS agent code execution</td></tr><tr><td>Daytona</td><td>Cloud sandbox</td><td>Medium (network)</td><td>N/A (managed)</td><td>Full dev environments with LSP</td></tr></tbody></table><h3 id="function-calling-libraries" tabindex="-1">Function Calling Libraries <a class="header-anchor" href="#function-calling-libraries" aria-label="Permalink to &quot;Function Calling Libraries&quot;">​</a></h3><ul><li><strong>Instructor</strong> — Reliable structured JSON from any LLM, built on Pydantic. Automatic retries with validation feedback, streaming partial objects, multi-provider support. 10 K+ stars, 3 M+ monthly downloads. <a href="https://github.com/jxnl/instructor" target="_blank" rel="noreferrer">https://github.com/jxnl/instructor</a></li><li><strong>Magentic</strong> — <code>@prompt</code> decorator turns a Python function signature into an LLM call with structured output. <code>FunctionCall</code> type lets the model choose which function to invoke; <code>@prompt_chain</code> auto-resolves tool loops. <a href="https://github.com/jackmpcollins/magentic" target="_blank" rel="noreferrer">https://github.com/jackmpcollins/magentic</a></li></ul><h3 id="code-editing-tools" tabindex="-1">Code Editing Tools <a class="header-anchor" href="#code-editing-tools" aria-label="Permalink to &quot;Code Editing Tools&quot;">​</a></h3><ul><li><strong>diff-match-patch</strong> — Google&#39;s battle-tested diff / match / patch library (2006). Myers&#39; diff + bitap fuzzy matching + best-effort patch application. Critical for agents: patches still apply when code has shifted. C++, JS, Python, Java, and more. <a href="https://github.com/google/diff-match-patch" target="_blank" rel="noreferrer">https://github.com/google/diff-match-patch</a></li><li><strong>Tree-sitter</strong> — Incremental parser generator producing concrete syntax trees for 200+ languages. Fast enough for per-keystroke parsing, robust with syntax errors. Enables syntax-aware edits, symbol extraction, and structural navigation. Used by Aider, Claude Code, Cursor. <a href="https://github.com/tree-sitter/tree-sitter" target="_blank" rel="noreferrer">https://github.com/tree-sitter/tree-sitter</a></li><li><strong>Language Server Protocol (LSP)</strong> — Microsoft protocol (spec 3.17) giving tools IDE-grade intelligence: diagnostics, go-to-definition, references, rename, completions. JSON-RPC based — directly inspired MCP&#39;s design. Agents use LSP for pre/post-edit validation and safe refactoring. <a href="https://microsoft.github.io/language-server-protocol/" target="_blank" rel="noreferrer">https://microsoft.github.io/language-server-protocol/</a></li></ul><table tabindex="0"><thead><tr><th>Tool</th><th>Type</th><th>Speed</th><th>Languages</th><th>Incremental</th><th>Primary Agent Use</th></tr></thead><tbody><tr><td>diff-match-patch</td><td>Diff / Patch</td><td>Very fast</td><td>Agnostic</td><td>N/A</td><td>Applying fuzzy code edits</td></tr><tr><td>Tree-sitter</td><td>Parser / CST</td><td>Very fast</td><td>200+ grammars</td><td>Yes</td><td>Syntax-aware navigation &amp; edits</td></tr><tr><td>LSP</td><td>Protocol</td><td>Varies</td><td>Per server</td><td>Yes</td><td>Diagnostics, refactoring, symbols</td></tr><tr><td>Universal Ctags</td><td>Indexer</td><td>Fast</td><td>200+</td><td>No (batch)</td><td>Symbol indexing for context</td></tr></tbody></table><h3 id="safety-guardrails" tabindex="-1">Safety &amp; Guardrails <a class="header-anchor" href="#safety-guardrails" aria-label="Permalink to &quot;Safety &amp; Guardrails&quot;">​</a></h3><ul><li><strong>NeMo Guardrails</strong> — NVIDIA&#39;s open-source toolkit (Apache 2.0) for adding programmable rails to LLM apps. Uses Colang DSL to define input/output/dialog/execution rails. Includes LLM vulnerability scanning against jailbreaks. Python 3.10–3.13. <a href="https://github.com/NVIDIA/NeMo-Guardrails" target="_blank" rel="noreferrer">https://github.com/NVIDIA/NeMo-Guardrails</a></li><li><strong>NVIDIA&#39;s layered approach</strong> — Input rails (prompt-injection detection, PII redaction) → output rails (code validation, harmful-content filtering) → execution rails (tool invocation control, rate limiting). Complements OS-level sandboxing with application-level safety.</li></ul><hr><h2 id="real-world-implementations" tabindex="-1">Real-World Implementations <a class="header-anchor" href="#real-world-implementations" aria-label="Permalink to &quot;Real-World Implementations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Approach</th><th>Reference</th></tr></thead><tbody><tr><td><strong>Codex</strong></td><td>3-layer sandbox (bubblewrap + seccomp + Landlock), execution policy engine</td><td><a href="./../agents/codex/tool-system.html"><code>../agents/codex/tool-system.md</code></a></td></tr><tr><td><strong>Goose</strong></td><td>MCP-native architecture, 7 extension types</td><td><a href="./../agents/goose/tool-system.html"><code>../agents/goose/tool-system.md</code></a></td></tr><tr><td><strong>OpenHands</strong></td><td>Action/observation model, 9 tools</td><td><a href="./../agents/openhands/tool-system.html"><code>../agents/openhands/tool-system.md</code></a></td></tr><tr><td><strong>OpenCode</strong></td><td>14 tools with permission system</td><td><a href="./../agents/opencode/tool-system.html"><code>../agents/opencode/tool-system.md</code></a></td></tr><tr><td><strong>Claude Code</strong></td><td>27-tool catalog, 5 permission modes</td><td><a href="./../agents/claude-code/tool-system.html"><code>../agents/claude-code/tool-system.md</code></a></td></tr><tr><td><strong>Gemini CLI</strong></td><td>18+ tools, multi-tier sandboxing</td><td><a href="./../agents/gemini-cli/tool-system.html"><code>../agents/gemini-cli/tool-system.md</code></a></td></tr><tr><td><strong>mini-SWE-agent</strong></td><td>Bash-only — no custom tool system</td><td><a href="./../agents/mini-swe-agent/tool-system.html"><code>../agents/mini-swe-agent/tool-system.md</code></a></td></tr><tr><td><strong>Aider</strong></td><td>6 edit formats (diff, whole, diff-fenced, architect)</td><td><a href="./../agents/aider/tool-system.html"><code>../agents/aider/tool-system.md</code></a></td></tr><tr><td><strong>π-coding-agent</strong></td><td>Radically extensible 4-tool system</td><td><a href="./../agents/pi-coding-agent/tool-system.html"><code>../agents/pi-coding-agent/tool-system.md</code></a></td></tr><tr><td><strong>Warp</strong></td><td>20+ tools, PTY interaction, Computer Use, LSP, Active AI error detection</td><td><a href="./../agents/warp/tool-system.html"><code>../agents/warp/tool-system.md</code></a></td></tr><tr><td><strong>Ante</strong></td><td>Rust-native, custom MCP SDK, bidirectional tool sharing</td><td><a href="./../agents/ante/tool-system.html"><code>../agents/ante/tool-system.md</code></a></td></tr><tr><td><strong>Droid</strong></td><td>Enterprise tools, Factory Analytics, GitHub Actions repair, Skills system</td><td><a href="./../agents/droid/tool-system.html"><code>../agents/droid/tool-system.md</code></a></td></tr><tr><td><strong>Junie CLI</strong></td><td>IDE+CLI dual-mode, 4-level permissions, 30+ tool functions</td><td><a href="./../agents/junie-cli/tool-system.html"><code>../agents/junie-cli/tool-system.md</code></a></td></tr><tr><td><strong>ForgeCode</strong></td><td>6 tools with tool-call correction layer, schema engineering</td><td><a href="./../agents/forgecode/tool-system.html"><code>../agents/forgecode/tool-system.md</code></a></td></tr><tr><td><strong>Sage-Agent</strong></td><td>ToolManager with MCP integration (stdio + SSE)</td><td><a href="./../agents/sage-agent/tool-system.html"><code>../agents/sage-agent/tool-system.md</code></a></td></tr><tr><td><strong>TongAgents</strong></td><td>Minimal confirmed tool set, multi-agent, benchmark-inferred</td><td><a href="./../agents/tongagents/tool-system.html"><code>../agents/tongagents/tool-system.md</code></a></td></tr><tr><td><strong>Capy</strong></td><td>Hard agent-tool boundaries, Ubuntu VM per task</td><td><a href="./../agents/capy/tool-system.html"><code>../agents/capy/tool-system.md</code></a></td></tr></tbody></table>`,168)])])}const h=s(n,[["render",l]]);export{u as __pageData,h as default};
